import zipfile, re
z = zipfile.ZipFile('output/settlement-agreement-markup.docx')
xml = z.read('word/document.xml').decode('utf-8')
# Reconstruct each paragraph's text with [INS:..]/[DEL:..] markers
import xml.etree.ElementTree as ET
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
root = ET.fromstring(xml)
body = root.find(W+'body')
def para_text(p):
    out=[]
    for el in p.iter():
        tag=el.tag
        if tag==W+'t':
            out.append(el.text or '')
        elif tag==W+'delText':
            out.append('[DEL:'+ (el.text or '') +']')
    # mark ins by walking
    return ''.join(out)
# Better: walk children in order
def render(p):
    parts=[]
    def walk(e, in_ins, in_del):
        for child in e:
            t=child.tag
            if t==W+'ins':
                walk(child, True, False)
            elif t==W+'del':
                walk(child, False, True)
            elif t==W+'r':
                walk(child, in_ins, in_del)
            elif t==W+'t':
                txt=child.text or ''
                parts.append(('[INS:'+txt+']') if in_ins else txt)
            elif t==W+'delText':
                parts.append('[DEL:'+(child.text or '')+']')
            else:
                walk(child, in_ins, in_del)
    walk(p, False, False)
    return ''.join(parts)
paras=[p for p in body if p.tag==W+'p']
# find paragraphs containing key changes
for i,p in enumerate(paras):
    r=render(p)
    if any(k in r for k in ['Twelve Dollars','537,500','twenty-one (21)','Revocation Period','to any federal, state','18 U.S.C.','Section 19','Section 22','neutral employment reference','five (5) years following','Oregon, Washington, and Idaho','Notwithstanding the foregoing']):
        print(f'--- para {i} ---')
        print(r[:600])
        print()
" 2>&1 | head -80"}

