import zipfile, re
import xml.etree.ElementTree as ET
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
z = zipfile.ZipFile('output/settlement-agreement-markup.docx')
xml = z.read('word/document.xml').decode('utf-8')
print('w:ins:', len(re.findall(r'<w:ins ', xml)), '| w:del:', len(re.findall(r'<w:del ', xml)))
root = ET.fromstring(xml); body = root.find(W+'body')
def render(p):
    parts=[]
    def walk(e, ii, idl):
        for c in e:
            t=c.tag
            if t==W+'ins': walk(c,True,False)
            elif t==W+'del': walk(c,False,True)
            elif t==W+'r':
                # check bold
                rpr=c.find(W+'rPr')
                b = rpr is not None and rpr.find(W+'b') is not None
                walk(c, ii, idl)
            elif t==W+'t': parts.append(('[I:'+(c.text or '')+']') if ii else (c.text or ''))
            elif t==W+'delText': parts.append('[D:'+(c.text or '')+']')
            else: walk(c, ii, idl)
    walk(p,False,False); return ''.join(parts)
paras=[p for p in body if p.tag==W+'p']
# Show the Effective Date change, RSU change, a new heading (check bold), revocation
for i,p in enumerate(paras):
    r=render(p)
    if ('Effective Date\" means' in r and 'eighth' in r) or 'Section 19. Return' in r or 'Revocation Period' in r or ('Twelve' in r) or ('five (5) years' in r):
        # check if heading bold
        bold = any(rr.find(W+'rPr') is not None and rr.find(W+'rPr').find(W+'b') is not None for rr in p.iter(W+'r'))
        print(f'--- para {i} (bold={bold}) ---')
        print(r[:300]); print()
""}

